async function run(agent) {
  await agent.aiTap("进入 Menu");
  await agent.aiTap("点击 Settings");
  await agent.aiTap("点击 Visualization");
  await agent.aiTap("启用 Show OK Code Field");
  await agent.aiTap("保存 Visualization 设置");
  const workbookParams = await agent.aiQuery("string, 读取工作簿 RBJP_BP_IT_B2P_RE-FX_YEC_LeaseLiab_Reclassification 中的测试参数。");
  await agent.aiTap("从 SAP Easy Access 用户菜单打开 Info System Reclassification。");
  await agent.aiTap("打开 Sort Method 搜索帮助。");
  await agent.aiTap("在 Sort Method 搜索结果中选择 sort method 1。");
  await agent.aiInput("Key date", { value: "<key date from workbook>" });
  await agent.aiTap("从 listbox shell 中选择匹配的 key date/参数条目。");
  await agent.aiTap("执行 Info System Reclassification。");
  await agent.aiAssert("确认出现 Reclassification (<Date>) 结果页。");
  await agent.aiTap("返回 SAP Easy Access。");
  await agent.aiInput("OK Code / command field", { value: "OBJREG" });
  await agent.aiKeyboardPress("Enter");
  await agent.aiTap("打开 Sort Method 搜索帮助并选择 sort method 2。");
  await agent.aiTap("打开 Valuation Area for FI Year End Closing 搜索帮助并选择 valuation area 2。");
  await agent.aiInput("Valuation key date", { value: "31.03.2026" });
  await agent.aiTap("切换到 Valuation objects 页签。");
  await agent.aiInput("Aggregation ledger", { value: "Bosch valuation ledger IFRS16" });
  await agent.aiInput("G/L account", { value: "<lease liabilities G/L account>" });
  await agent.aiInput("Identif. val. obj", { value: "<valuation object id>" });
  await agent.aiTap("切换到 Parameters 页签。");
  await agent.aiTap("切换到 Postings 页签。");
  await agent.aiTap("点击执行图标 sap_180 进行测试运行/生成日志。");
  await agent.aiTap("点击 Messages 查看 Display logs。");
  await agent.aiAssert("确认 Display logs 中没有阻断性错误。");
  await agent.aiTap("返回 Sorted Valuation Objects 页面，并确认 Post documents immediately 选项。");
  await agent.aiInput("Debit flow type", { value: "<debit flow type>" });
  await agent.aiInput("Credit flow type", { value: "L40" });
  await agent.aiTap("切换到 Postings 页签，并确认 Perform test run。");
  await agent.aiTap("点击执行图标 sap_180 并打开 Messages。");
  await agent.aiTap("返回后取消/关闭 test run 标记，准备正式 posting。");
  await agent.aiTap("再次点击执行图标 sap_180 进行正式过账。");
  await agent.aiTap("打开 Postings 结果并返回。");
  await agent.aiAssert("确认 IFRS16 lease liability reclassification 运行完成，日志/过账结果无错误。");
}
